export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(keyOf));
  const survivors = liveCells.filter((cell) => {
    const n = countLiveNeighbors(cell, alive);
    return n === 2 || n === 3;
  });
  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const key = keyOf([nx, ny]);
      if (!alive.has(key)) candidates.set(key, [nx, ny]);
    }
  }
  const born: Cell[] = [];
  for (const cell of candidates.values()) {
    if (countLiveNeighbors(cell, alive) === 3) born.push(cell);
  }
  return [...survivors, ...born];
}

